```typescript
import { expect, test } from '@playwright/test';

test('should render checkout form', async ({ page }) => {
  await page.goto('/checkout');
  await expect(
    page.getByRole('region', { name: 'Checkout' }),
  ).toMatchAriaSnapshot(`
    - heading "Checkout" [level=1]
    - textbox "Email"
    - button "Place Order"
  `);
});
```

```typescript
test('should show validation error on empty submit', async ({ page }) => {
  await page.goto('/checkout');
  await page.getByRole('button', { name: 'Place Order' }).click();
  await expect(
    page.getByRole('region', { name: 'Checkout' }),
  ).toMatchAriaSnapshot(`
    - textbox "Email" [invalid=true]
    - text: "Email is required"
  `);
});
```

```typescript
// e2e/fixtures/checkout.fixture.ts
import { test as base, expect } from '@playwright/test';
import { CheckoutPage } from './checkout.page';

export const test = base.extend<{ checkout: CheckoutPage }>({
  checkout: async ({ page }, use) => {
    await use(new CheckoutPage(page));
  },
});
export { expect };

// e2e/tests/checkout.spec.ts
import { expect, test } from '../fixtures/checkout.fixture';

test('happy path', async ({ checkout }) => {
  await checkout.navigate();
  await checkout.fillEmail('user@test.com');
  await checkout.submit();
  await expect(checkout.confirmation).toMatchAriaSnapshot(`
    - heading "Order placed" [level=1]
  `);
});
```

