```typescript
test('should show confirmation when order API succeeds', async ({ page }) => {
  await page.route('**/api/orders', async (route) => {
    await route.fulfill({
      status: 200,
      contentType: 'application/json',
      body: JSON.stringify({ orderId: 'ord-1', status: 'confirmed' }),
    });
  });
  await page.goto('/checkout');
  await page.getByRole('button', { name: 'Place Order' }).click();
  await expect(page.getByRole('status')).toContainText('Order ord-1');
});
```
